I haven't really worked with GOLANG before so I apologise for the **what-ever-the-heck** pattern I tried to follow here. The most usefull thing from this should be the REGEX and the documentation which was the most difficult to obtain.

REGEX (single): `^(u?g?o?|a)([-+=])(\b)(r?w?x?X?s?t?u?g?o?)$`
REGEX (mutiple): `^((u?g?o?|a)([-+=])(\b)(r?w?x?X?s?t?u?g?o?),?)+$` 

[CHMOD documentation](https://ss64.com/osx/chmod.html)

<details>
  <summary>chmod.go</summary>

```go
package libs

import (
	"fmt"
	"os"
	"regexp"
	"strconv"
)

// Intention:
// The idea is that a MaybeChmod is user input or input that you are unsure about.
// You can convert that UNSURE input to a SURE unit or properly handle it if it isn't.
// The VALID forms can be used by developers but are unchecked and will break stuff if you give it bad input.

type (
	MaybeChmod        string //Represents an string that COULD BE a valid chmod form
	ChmodAbsoluteForm uint32 //Represents a VALID chmod absolute uint32 `Parameter`
	ChmodSymbolicForm string //Represents a VALID chmod symbolic string `Parameter`
	ChmodForm         interface {
		Chmod() Chmod //turns a VALID chmod form into it's workable object
	} //Represents a VALID chmod form
	Chmod interface {
		Apply(c ChmodAbsoluteForm) uint32          //applies chmod description
		ApplyToInt16(c uint16) uint16              //applies chmod description to [int16]
		ApplyToUInt32(c uint32) uint32             //applies chmod description to [unit32]
		ApplyToUnint64(c uint64) uint64            //applies chmod description to [unit64]
		ApplyToFileMode(c os.FileMode) os.FileMode //applies chmod description to [filemode]
		String() string                            //Returns FRENDLY representation string
	} //Represents a chmod unit
)

type ChmodAbsolute struct {
	ChmodAbsoluteForm
} // VALID Absolute Chmod unit

type ChmodSybolicMask uint32 // Symbolic Mask Parameter
type ChmodSymbolic struct {
	ChmodSymbolicForm
	ChmodSybolicAddition    ChmodSybolicMask
	ChmodSybolicSubtraction ChmodSybolicMask
	ChmodSybolicAbsolute    ChmodSybolicMask
} // VALID Symbolic Chmod unit

const (
	ChmodMaxAbsoluteValue uint32 = 0o7777 //maximum allowed chmod absolute value
	ChmodMinAbsoluteValue uint32 = 0o0000 //minimum allowed chmod absolute value
	ChmodParameterRegex          = `^(u?g?o?|a)([-+=])(\b)(r?w?x?X?s?t?u?g?o?)$`
	ChmodParametersRegex         = `^((u?g?o?|a)([-+=])(\b)(r?w?x?X?s?t?u?g?o?),?)+$`
	ChmodSymbolicDoc             = "README.md" //where to find information on the symbolic form
)

var (
	ChmodParameterPatern  = regexp.MustCompile(ChmodParametersRegex) //should match a single parameter set; where the `,` have been split out
	ChmodParametersPatern = regexp.MustCompile(ChmodParametersRegex) //should match full list of parameters
)

// https://ss64.com/osx/chmod.html
// SYMBOLIC MODE MODE
/*	# Form
	`[who...][[+-=][perm...]...][,...]`

	who - a combination of the letters `ugoa` controls which users' access to the file will be changed:
		u The User who owns it
		g other users in the file's Group
		o Other users not in the file's group
		a All users, this is equivalent to (ugo)
		If none of these are given, the effect is as if (a) were given, but bits that are set in the umask are not affected.

	+-=
		The operator '+' causes the permissions selected to be added to the existing permissions of each file;
		'-' causes them to be removed; and '=' causes them to be the only permissions that the file has.
		if = is specified with no who then all (owner, group and other) will be cleared.

	perm - The letters 'rwxXstugo' select the new permissions for the affected users:
		r Read
		w Write
		x Execute/search (or access for directories)
		X Execute/search only if the file is a directory or already has execute permission for some user
		s Set user or group ID on execution
		t The sticky bit
		u User permission
		g Group permission
		o Other permission (users not in the file's group)

	# Symbolic Mode Examples
		Deny execute permission to everyone:
		$ `chmod a-x file`

		Allow read permission to everyone:
		$ `chmod a+r file`

		Make a file readable and writable by the group and others:
		$ `chmod go+rw file`

		Make a shell script executable by the user/owner
		$ `chmod u+x myscript.sh`

		Allow everyone to read, write, and execute the file and turn on the set group-ID:
		$ `chmod =rwx,g+s file`
*/
// NUMERIC MODE
/*
    From one to four octal digits [oooo]
    Any omitted digits are assumed to be leading zeros. [0ooo]

	| Bit Name | Position | Valid Values | Directory Context |
	|----|----|----|----|
	| Atribute Bit | [x000] | 4 (User ID), 2 (Group ID), 1 (Sticky) | None |
	| User (Owner) Bit | [0x00] | 4 (Read), 2 (Write), 1 (Exec) | 1 (Owner User Search) |
	| Group Bit | [00x0] | 4 (Read), 2 (Write), 1 (Exec) | 1 (Group Search) |
	| Others Bit | [000x] | 4 (Read), 2 (Write), 1 (Exec) | 1 (Others Search) |

    The octal (0-7) value is calculated by adding up the values for each digit
    User (rwx) = 4+2+1 = 7
    Group (rx) = 4+1 = 5
    World (rx) = 4+1 = 5
    chmod mode = 0755

    # Numeric Mode Examples:
		Allow read permission to everyone:
		$ chmod 444 file

		Allow everyone to read, and execute the file:
		$ chmod 755 file

		Make a file readable by anyone and writable by the owner only:
		$ chmod 644 file

		Make a file readable and writable by the group and others:
		$ chmod 066 file

*/

//----[MaybeChmod]----

// tests if [MaybeChmod] is empty
func (mch MaybeChmod) isEmpty() bool {
	return mch == ""
}

// converts a [MaybeChmod] to the [ChmodSymbolicForm]
func (mch MaybeChmod) chmodSymbolicForm() (ChmodForm, error) {
	//addtional validation?
	if !ChmodParametersPatern.MatchString(string(mch)) {
		return nil, fmt.Errorf("value '%s' was not in the correct chmod-symbolic format. Please see %s for information on the correct format", mch, ChmodSymbolicDoc)
	}
	return ChmodSymbolicForm(mch), nil
}

// tests:
// 	succeed: u+r ; +r ; +rw ; a+r ; +u ; +rwx ; u+x,g+r,o+x ; u-x ; a=rwx ; +rwxXstugo  (unsure)
//	fail: + ; ua+r (all was spesified) ; r ; w ; u+lol ; a+ ; lol+x ; uu+x ; g+rr

// converts a [MaybeChmod] to the [ChmodAbsoluteForm]
func (mch MaybeChmod) chmodAbsoluteForm() (ChmodForm, error) {
	//addtional validation?
	ui64, err := strconv.ParseUint(string(mch), 8, 32)
	if err != nil {
		return nil, fmt.Errorf("absolute: %w", err) //TODO: what is the top level tag?
	}
	ui32 := uint32(ui64)
	if !(ui32 <= ChmodMaxAbsoluteValue && ui32 >= ChmodMinAbsoluteValue) { //min will never be false. put here for completeness
		return nil, fmt.Errorf("absolute: value is not in valid range: %04o <= '%04o' >= %04o", ChmodMaxAbsoluteValue, ui32, ChmodMinAbsoluteValue)
	}
	return ChmodAbsoluteForm(ui32), nil
}

// might return chmod form
func (mch MaybeChmod) MaybeChmodForm() (ChmodForm, error) {
	if mch.isEmpty() {
		return nil, fmt.Errorf("maybeChmod.MaybeChmod: empty value")
	}
	chmodform, aerr := mch.chmodAbsoluteForm()
	if chmodform != nil {
		//if we have a return, it means the input was in symbolic format
		return chmodform, nil
	}
	chmodform, serr := mch.chmodSymbolicForm()
	if chmodform != nil {
		//if we have a return, it means the input was in absolute format
		return chmodform, nil
	}
	//if we get here it means it was in neither format. we don't know what the problem is, so we send back both errors
	err := fmt.Errorf("[%v, %v]", serr, aerr)
	return nil, fmt.Errorf("maybeChmod.MaybeChmod: %w", err)
}

// might return chmod
func (mch MaybeChmod) MaybeChmod() (Chmod, error) {
	chmodform, err := mch.MaybeChmodForm()
	if err != nil {
		return nil, fmt.Errorf("MaybeChmod: %w", err)
	}
	return chmodform.Chmod(), nil
}

//----[ChmodAbsoluteForm]----

func (caf ChmodAbsoluteForm) FileMode() os.FileMode {
	return os.FileMode(caf)
}

func (caf ChmodAbsoluteForm) Chmod() Chmod {
	return ChmodAbsolute{
		ChmodAbsoluteForm: caf,
	}
}

// should print the friendly representation of the absolute chmod 4chars leftpadded with 0
func (caf ChmodAbsoluteForm) String() string {
	return fmt.Sprintf("%04o", caf)
}

//----[ChmodSymbolicForm]----

func (csf ChmodSymbolicForm) Chmod() Chmod {
	//TODO: parse parse parse
	return ChmodSymbolic{
		ChmodSymbolicForm: csf,
	}
}

func (csf ChmodSymbolicForm) String() string {
	return string(csf)
}

//----[ChmodAbsolute]----

// should always overide

func (ca ChmodAbsolute) Apply(c ChmodAbsoluteForm) uint32 {
	return uint32(ca.ChmodAbsoluteForm)
}
func (ca ChmodAbsolute) ApplyToInt16(c uint16) uint16 {
	return uint16(ca.ChmodAbsoluteForm)
}
func (ca ChmodAbsolute) ApplyToUInt32(c uint32) uint32 {
	return uint32(ca.ChmodAbsoluteForm)
}
func (ca ChmodAbsolute) ApplyToUnint64(c uint64) uint64 {
	return uint64(ca.ChmodAbsoluteForm)
}
func (ca ChmodAbsolute) ApplyToFileMode(c os.FileMode) os.FileMode {
	return ca.ChmodAbsoluteForm.FileMode()
}
func (ca ChmodAbsolute) String() string {
	return ca.ChmodAbsoluteForm.String()
}

//----[ChmodMask]----

func (cm ChmodSybolicMask) String() string {
	return fmt.Sprintf("%04o", cm)
}

func (cm ChmodSybolicMask) PrettyString() string {
	//todo: pretty string
	return cm.String()
}

//----[ChmodSymbolic]----

// should "apply" (overide, add, subtract) the different parts of the form to the given value

func (cs ChmodSymbolic) Apply(c ChmodAbsoluteForm) uint32 {
	ret := uint32(c)
	return cs.ApplyToUInt32(ret)
}
func (cs ChmodSymbolic) ApplyToInt16(c uint16) uint16 {
	ret := c
	ret |= uint16(cs.ChmodSybolicAddition)
	ret &^= uint16(cs.ChmodSybolicSubtraction)
	ret |= uint16(cs.ChmodSybolicAbsolute) //what is the order of operations here? does absolute overide subtractions?
	return uint16(ret)
}
func (cs ChmodSymbolic) ApplyToUInt32(c uint32) uint32 {
	ret := c
	ret |= uint32(cs.ChmodSybolicAddition)
	ret &^= uint32(cs.ChmodSybolicSubtraction)
	ret |= uint32(cs.ChmodSybolicAbsolute) //what is the order of operations here? does absolute overide subtractions?
	return uint32(ret)
}
func (cs ChmodSymbolic) ApplyToUnint64(c uint64) uint64 {
	ret := c
	ret |= uint64(cs.ChmodSybolicAddition)
	ret &^= uint64(cs.ChmodSybolicSubtraction)
	ret |= uint64(cs.ChmodSybolicAbsolute) //what is the order of operations here? does absolute overide subtractions?
	return uint64(ret)
}
func (cs ChmodSymbolic) ApplyToFileMode(c os.FileMode) os.FileMode {
	ui32 := uint32(c)
	applied := cs.ApplyToUInt32(ui32)
	return os.FileMode(applied)
}
func (cs ChmodSymbolic) String() string {
	return cs.ChmodSymbolicForm.String()
}
```

